('about', 'about_title', 'en', 'About us'),
('about', 'about_title', 'ru', 'О нас'),
('about', 'about_why_bank', 'he', 'הפלטפורמה שלנו מאפשרת לשלוח בקשה לכל הבנקים ולקבל את ההצעות הכי משתלמות, ללא יציאה מהבית.'),
