('legal', 'privacy_policy_section_13_1', 'he', '**13.1 ניסיון גישור:** כל סכסוך הקשור לפרטיות יטופל תחילה באמצעות ניסיונות גישור ובוררות.'),
('legal', 'privacy_policy_section_13_1', 'en', '**13.1 Mediation Attempt:** Any privacy-related dispute will first be handled through mediation and arbitration attempts.'),
('legal', 'privacy_policy_section_13_1', 'ru', '**13.1 Попытка посредничества:** Любой спор, связанный с конфиденциальностью, будет сначала рассматриваться через попытки посредничества и арбитража.'),
('legal', 'privacy_policy_section_13_2', 'he', '**13.2 סמכות שיפוט:** סמכות השיפוט הבלעדית לסכסוכים נתונה לבתי המשפט בתל אביב.'),
('legal', 'privacy_policy_section_13_2', 'en', '**13.2 Jurisdiction:** Exclusive jurisdiction for disputes lies with the courts in Tel Aviv.'),
('legal', 'privacy_policy_section_13_2', 'ru', '**13.2 Юрисдикция:** Исключительная юрисдикция по спорам принадлежит судам в Тель-Авиве.'),
('legal', 'privacy_policy_section_13_3', 'he', '**13.3 דין החל:** מדיניות זו כפופה לחוקי מדינת ישראל.'),
('legal', 'privacy_policy_section_13_3', 'en', '**13.3 Applicable Law:** This policy is governed by the laws of the State of Israel.'),
('legal', 'privacy_policy_section_13_3', 'ru', '**13.3 Применимое право:** Эта политика регулируется законами государства Израиль.'),
('legal', 'privacy_policy_section_13_title', 'he', '**13. פתרון סכסוכים**'),
('legal', 'privacy_policy_section_13_title', 'en', '**13. Dispute Resolution**'),
('legal', 'privacy_policy_section_13_title', 'ru', '**13. Разрешение споров**'),
('legal', 'privacy_policy_section_14_1', 'he', '**14.1 נתונים רגישים:** מידע רפואי, אמונות דתיות, דעות פוליטיות ומידע ביומטרי נחשבים לנתונים רגישים הדורשים הגנה מוגברת.'),
('legal', 'privacy_policy_section_14_1', 'en', '**14.1 Sensitive Data:** Health information, religious beliefs, political views, and biometric information are considered sensitive data requiring enhanced protection.'),
('legal', 'privacy_policy_section_14_1', 'ru', '**14.1 Конфиденциальные данные:** Медицинская информация, религиозные убеждения, политические взгляды и биометрическая информация считаются конфиденциальными данными, требующими усиленной защиты.'),
('legal', 'privacy_policy_section_14_2', 'he', '**14.2 עיבוד אוטומטי:** כל החלטה אוטומטית המשפיעה עליכם באופן משמעותי תאפשר התערבות אנושית וערעור.'),
('legal', 'privacy_policy_section_14_2', 'en', '**14.2 Automated Processing:** Any automated decision significantly affecting you will allow for human intervention and appeal.'),
('legal', 'privacy_policy_section_14_2', 'ru', '**14.2 Автоматизированная обработка:** Любое автоматизированное решение, существенно влияющее на вас, позволит человеческое вмешательство и обжалование.'),
('legal', 'privacy_policy_section_14_title', 'he', '**14. הגדרות מיוחדות**'),
('legal', 'privacy_policy_section_14_title', 'en', '**14. Special Definitions**'),
('legal', 'privacy_policy_section_14_title', 'ru', '**14. Специальные определения**'),
('legal', 'privacy_policy_section_15', 'he', 'במקרה של הפרת אבטחה או חשד להפרה, נפעל מיידית לזהות את הבעיה, ננקוט באמצעי תיקון ונודיע לכם ולרשויות המתאימות תוך 72 שעות, בהתאם לדרישות החוק.'),
('legal', 'privacy_policy_section_15', 'en', 'In case of security breach or suspected breach, we will act immediately to identify the problem, take corrective measures, and notify you and appropriate authorities within 72 hours, in accordance with legal requirements.'),
('legal', 'privacy_policy_section_15', 'ru', 'В случае нарушения безопасности или подозрения на нарушение мы немедленно примем меры для выявления проблемы, предпримем корректирующие меры и уведомим вас и соответствующие органы в течение 72 часов в соответствии с правовыми требованиями.'),
('legal', 'privacy_policy_section_15_title', 'he', '**15. חירום ותקלות**'),
('legal', 'privacy_policy_section_15_title', 'en', '**15. Emergency and Malfunctions**'),
('legal', 'privacy_policy_section_15_title', 'ru', '**15. Чрезвычайные ситуации и неисправности**'),
('legal', 'privacy_policy_section_16_1', 'he', '**16.1 זמינות:** צוות התמיכה שלנו זמין לכל שאלה הקשורה לפרטיות באמצעים המפורטים להלן.'),
('legal', 'privacy_policy_section_16_1', 'en', '**16.1 Availability:** Our support team is available for any privacy-related questions through the means detailed below.'),
('legal', 'privacy_policy_section_16_1', 'ru', '**16.1 Доступность:** Наша команда поддержки доступна для любых вопросов, связанных с конфиденциальностью, через средства, подробно описанные ниже.'),
('legal', 'privacy_policy_section_16_2', 'he', '**16.2 הדרכה מתמחה:** נציגי השירות עברו הדרכה מתמחה בנושאי הגנת פרטיות וזכויות הפרט.'),
('legal', 'privacy_policy_section_16_2', 'en', '**16.2 Specialized Training:** Service representatives have undergone specialized training in privacy protection and individual rights.'),
('legal', 'privacy_policy_section_16_2', 'ru', '**16.2 Специализированное обучение:** Представители службы прошли специализированное обучение по вопросам защиты конфиденциальности и прав личности.'),
('legal', 'privacy_policy_section_16_title', 'he', '**16. תמיכה ושירות לקוחות**'),
('legal', 'privacy_policy_section_16_title', 'en', '**16. Support and Customer Service**'),
('legal', 'privacy_policy_section_16_title', 'ru', '**16. Поддержка и обслуживание клиентов**'),
('legal', 'privacy_policy_section_17_1', 'he', 'לכל שאלה או בקשה הקשורה למדיניות הפרטיות שלנו, אנא צרו איתנו קשר:'),
('legal', 'privacy_policy_section_17_1', 'en', 'For any questions or requests related to our privacy policy, please contact us:'),
('legal', 'privacy_policy_section_17_1', 'ru', 'По любым вопросам или запросам, связанным с нашей политикой конфиденциальности, пожалуйста, свяжитесь с нами:'),
('legal', 'privacy_policy_section_17_address', 'he', '**כתובת:** רחוב הבנקאים 15, תל אביב 6812345'),
('legal', 'privacy_policy_section_17_address', 'en', '**Address:** Habankaim Street 15, Tel Aviv 6812345'),
('legal', 'privacy_policy_section_17_address', 'ru', '**Адрес:** ул. Хабанкаим 15, Тель-Авив 6812345'),
('legal', 'privacy_policy_section_17_email', 'he', '**דואר אלקטרוני:** privacy@bankimonline.com | **קצין הגנת נתונים:** dpo@bankimonline.com'),
('legal', 'privacy_policy_section_17_email', 'en', '**Email:** privacy@bankimonline.com | **Data Protection Officer:** dpo@bankimonline.com'),
('legal', 'privacy_policy_section_17_email', 'ru', '**Электронная почта:** privacy@bankimonline.com | **Сотрудник по защите данных:** dpo@bankimonline.com'),
('legal', 'privacy_policy_section_17_phone', 'he', '**טלפון:** 03-5371622'),
('legal', 'privacy_policy_section_17_phone', 'en', '**Phone:** 03-5371622'),
('legal', 'privacy_policy_section_17_phone', 'ru', '**Телефон:** 03-5371622'),
('legal', 'privacy_policy_section_17_title', 'he', '**17. צרו קשר**'),
('legal', 'privacy_policy_section_17_title', 'en', '**17. Contact Us**'),
('legal', 'privacy_policy_section_17_title', 'ru', '**17. Свяжитесь с нами**'),
('legal', 'privacy_policy_section_1_1', 'he', '**1.1 מידע אישי:** אנו אוספים מידע אישי שאתם מספקים לנו מרצונכם החופשי, כגון שם מלא, מספר טלפון, כתובת דואר אלקטרוני, תאריך לידה ומספר תעודת זהות.'),
('legal', 'privacy_policy_section_1_1', 'en', '**1.1 Personal Information:** We collect personal information that you provide to us voluntarily, such as full name, phone number, email address, date of birth, and ID number.'),
('legal', 'privacy_policy_section_1_1', 'ru', '**1.1 Персональная информация:** Мы собираем персональную информацию, которую вы предоставляете нам добровольно, такую как полное имя, номер телефона, адрес электронной почты, дату рождения и номер удостоверения личности.'),
('legal', 'privacy_policy_section_1_2', 'he', '**1.2 מידע פיננסי:** במסגרת בקשות למשכנתא או אשראי, אנו עשויים לאסוף מידע על מצבכם הפיננסי, לרבות הכנסות, הוצאות, נכסים והתחייבויות.'),
('legal', 'privacy_policy_section_1_2', 'en', '**1.2 Financial Information:** As part of mortgage or credit applications, we may collect information about your financial situation, including income, expenses, assets, and liabilities.'),
('legal', 'privacy_policy_section_1_2', 'ru', '**1.2 Финансовая информация:** В рамках заявок на ипотеку или кредит мы можем собирать информацию о вашем финансовом положении, включая доходы, расходы, активы и обязательства.'),
('legal', 'privacy_policy_section_1_3', 'he', '**1.3 מידע טכני:** אנו אוספים אוטומטית מידע על השימוש שלכם באתר, לרבות כתובת IP, סוג דפדפן, מערכת הפעלה ועמודים שנצפו.'),
('legal', 'privacy_policy_section_1_3', 'en', '**1.3 Technical Information:** We automatically collect information about your use of the website, including IP address, browser type, operating system, and pages visited.'),
('legal', 'privacy_policy_section_1_3', 'ru', '**1.3 Техническая информация:** Мы автоматически собираем информацию о вашем использовании веб-сайта, включая IP-адрес, тип браузера, операционную систему и посещенные страницы.'),
('legal', 'privacy_policy_section_1_4', 'he', '**1.4 עוגיות:** אנו משתמשים בעוגיות וטכנולוגיות דומות לשיפור חוויית האתר ולמטרות אנליטיות.'),
('legal', 'privacy_policy_section_1_4', 'en', '**1.4 Cookies:** We use cookies and similar technologies to improve website experience and for analytical purposes.'),
('legal', 'privacy_policy_section_1_4', 'ru', '**1.4 Файлы cookie:** Мы используем файлы cookie и аналогичные технологии для улучшения работы веб-сайта и в аналитических целях.'),
('legal', 'privacy_policy_section_1_5', 'he', '**1.5 מידע ממקורות חיצוניים:** אנו עשויים לקבל מידע עליכם מבנקים שותפים, סוכנויות דיווח אשראי וגופים אחרים במסגרת הערכת סיכון אשראי.'),
('legal', 'privacy_policy_section_1_5', 'en', '**1.5 Information from External Sources:** We may receive information about you from partner banks, credit reporting agencies, and other entities as part of credit risk assessment.'),
('legal', 'privacy_policy_section_1_5', 'ru', '**1.5 Информация из внешних источников:** Мы можем получать информацию о вас от банков-партнеров, агентств кредитной отчетности и других организаций в рамках оценки кредитного риска.'),
('legal', 'privacy_policy_section_1_title', 'he', '**1. מידע שאנו אוספים**'),
('legal', 'privacy_policy_section_1_title', 'en', '**1. Information We Collect**'),
('legal', 'privacy_policy_section_1_title', 'ru', '**1. Информация, которую мы собираем**'),
('legal', 'privacy_policy_section_2_1', 'he', '**2.1 מטרת השירות:** אנו משתמשים במידע שלכם למתן שירותי השוואת משכנתאות ואשראי, עיבוד בקשותיכם והצגת הצעות מתאימות מבנקים שותפים.'),
('legal', 'privacy_policy_section_2_1', 'en', '**2.1 Service Purpose:** We use your information to provide mortgage and credit comparison services, process your applications, and present suitable offers from partner banks.'),
('legal', 'privacy_policy_section_2_1', 'ru', '**2.1 Цель обслуживания:** Мы используем вашу информацию для предоставления услуг сравнения ипотеки и кредитов, обработки ваших заявок и представления подходящих предложений от банков-партнеров.'),
('legal', 'privacy_policy_section_2_2', 'he', '**2.2 שיפור השירות:** אנו משתמשים במידע לשיפור האתר והשירותים שלנו, פיתוח מוצרים חדשים וביצוע מחקר סטטיסטי.'),
('legal', 'privacy_policy_section_2_2', 'en', '**2.2 Service Improvement:** We use information to improve our website and services, develop new products, and conduct statistical research.'),
('legal', 'privacy_policy_section_2_2', 'ru', '**2.2 Улучшение услуг:** Мы используем информацию для улучшения нашего веб-сайта и услуг, разработки новых продуктов и проведения статистических исследований.'),
('legal', 'privacy_policy_section_2_2_1', 'he', '**2.2.1** ניתוח התנהגות משתמשים לשיפור חוויית האתר'),
('legal', 'privacy_policy_section_2_2_1', 'en', '**2.2.1** User behavior analysis to improve website experience'),
('legal', 'privacy_policy_section_2_2_1', 'ru', '**2.2.1** Анализ поведения пользователей для улучшения работы веб-сайта'),
('legal', 'privacy_policy_section_2_2_2', 'he', '**2.2.2** פיתוח כלי חישוב משכנתא ואשראי חדשים'),
('legal', 'privacy_policy_section_2_2_2', 'en', '**2.2.2** Development of new mortgage and credit calculation tools'),
('legal', 'privacy_policy_section_2_2_2', 'ru', '**2.2.2** Разработка новых инструментов расчета ипотеки и кредитов'),
('legal', 'privacy_policy_section_2_2_3', 'he', '**2.2.3** מחקר שוק להבנת צרכי הלקוחות'),
('legal', 'privacy_policy_section_2_2_3', 'en', '**2.2.3** Market research to understand customer needs'),
('legal', 'privacy_policy_section_2_2_3', 'ru', '**2.2.3** Исследование рынка для понимания потребностей клиентов'),
('legal', 'privacy_policy_section_2_2_4', 'he', '**2.2.4** ייעול תהליכי הגשת בקשות ואישורים'),
('legal', 'privacy_policy_section_2_2_4', 'en', '**2.2.4** Optimization of application and approval processes'),
('legal', 'privacy_policy_section_2_2_4', 'ru', '**2.2.4** Оптимизация процессов подачи заявок и одобрения'),
('legal', 'privacy_policy_section_2_2_5', 'he', '**2.2.5** יצירת דוחות סטטיסטיים ללא זיהוי אישי'),
('legal', 'privacy_policy_section_2_2_5', 'en', '**2.2.5** Creation of statistical reports without personal identification'),
('legal', 'privacy_policy_section_2_2_5', 'ru', '**2.2.5** Создание статистических отчетов без персональной идентификации'),
('legal', 'privacy_policy_section_2_title', 'he', '**2. שימוש במידע**'),
('legal', 'privacy_policy_section_2_title', 'en', '**2. Use of Information**'),
('legal', 'privacy_policy_section_2_title', 'ru', '**2. Использование информации**'),
('legal', 'privacy_policy_section_3_1', 'he', '**3.1 בנקים שותפים:** אנו עשויים לשתף את המידע שלכם עם בנקים שותפים לקבלת הצעות משכנתא או אשראי, רק לאחר קבלת הסכמתכם המפורשת.'),
('legal', 'privacy_policy_section_3_1', 'en', '**3.1 Partner Banks:** We may share your information with partner banks to obtain mortgage or credit offers, only after receiving your explicit consent.'),
('legal', 'privacy_policy_section_3_1', 'ru', '**3.1 Банки-партнеры:** Мы можем делиться вашей информацией с банками-партнерами для получения предложений по ипотеке или кредитам, только после получения вашего явного согласия.'),
('legal', 'privacy_policy_section_3_10', 'he', '**3.10 בקשת סירוב:** ניתן לבקש לא לשתף את המידע שלכם עם בנקים או גופים ספציפיים.'),
('legal', 'privacy_policy_section_3_10', 'en', '**3.10 Opt-out Request:** You may request not to share your information with specific banks or entities.'),
('legal', 'privacy_policy_section_3_10', 'ru', '**3.10 Запрос на отказ:** Вы можете запросить не делиться вашей информацией с конкретными банками или организациями.'),
('legal', 'privacy_policy_section_3_11', 'he', '**3.11 הודעת שיתוף:** אנו מתחייבים ליידע אתכם על כל שיתוף מידע המתרחש.'),
('legal', 'privacy_policy_section_3_11', 'en', '**3.11 Sharing Notification:** We commit to informing you of any information sharing that occurs.'),
('legal', 'privacy_policy_section_3_11', 'ru', '**3.11 Уведомление об обмене:** Мы обязуемся информировать вас о любом обмене информацией, который происходит.'),
('legal', 'privacy_policy_section_3_12', 'he', '**3.12 זכות נסיגה:** ניתן לחזור בכם מהסכמה לשיתוף מידע בכל עת.'),
('legal', 'privacy_policy_section_3_12', 'en', '**3.12 Withdrawal Right:** You may withdraw consent for information sharing at any time.'),
('legal', 'privacy_policy_section_3_12', 'ru', '**3.12 Право отзыва:** Вы можете отозвать согласие на обмен информацией в любое время.'),
('legal', 'privacy_policy_section_3_2', 'he', '**3.2 ספקי שירות:** אנו עשויים לשתף מידע עם ספקי שירות חיצוניים המסייעים לנו בהפעלת האתר ומתן השירותים, כגון ספקי אחסון נתונים, שירותי תשלום וחברות מחקר שוק.'),
('legal', 'privacy_policy_section_3_2', 'en', '**3.2 Service Providers:** We may share information with external service providers who assist us in operating the website and providing services, such as data storage providers, payment services, and market research companies.'),
('legal', 'privacy_policy_section_3_2', 'ru', '**3.2 Поставщики услуг:** Мы можем делиться информацией с внешними поставщиками услуг, которые помогают нам в работе веб-сайта и предоставлении услуг, такими как поставщики хранения данных, платежные сервисы и компании по исследованию рынка.'),
('legal', 'privacy_policy_section_3_3', 'he', '**3.3 דרישות חוק:** אנו עשויים לחשוף מידע אישי כאשר נדרש על פי חוק או צו בית משפט, או להגנה על זכויותינו, רכושנו או בטיחות המשתמשים.'),
('legal', 'privacy_policy_section_3_3', 'en', '**3.3 Legal Requirements:** We may disclose personal information when required by law or court order, or to protect our rights, property, or user safety.'),
('legal', 'privacy_policy_section_3_3', 'ru', '**3.3 Правовые требования:** Мы можем раскрывать персональную информацию, когда это требуется по закону или решению суда, или для защиты наших прав, собственности или безопасности пользователей.'),
('legal', 'privacy_policy_section_3_4', 'he', '**3.4 מיזוגים ורכישות:** במקרה של מיזוג, רכישה או מכירת נכסים, מידע אישי עשוי להיות מועבר לצד הרוכש כחלק מהעסקה.'),
('legal', 'privacy_policy_section_3_4', 'en', '**3.4 Mergers and Acquisitions:** In case of merger, acquisition, or asset sale, personal information may be transferred to the acquiring party as part of the transaction.'),
('legal', 'privacy_policy_section_3_4', 'ru', '**3.4 Слияния и поглощения:** В случае слияния, поглощения или продажи активов персональная информация может быть передана приобретающей стороне как часть сделки.'),
('legal', 'privacy_policy_section_3_5', 'he', '**3.5 הסכמה מפורשת:** כל שיתוף של מידע רגיש יתבצע רק לאחר קבלת הסכמתכם המפורשת והמוקדמת.'),
('legal', 'privacy_policy_section_3_5', 'en', '**3.5 Explicit Consent:** Any sharing of sensitive information will only occur after obtaining explicit and prior consent from you.'),
('legal', 'privacy_policy_section_3_5', 'ru', '**3.5 Явное согласие:** Любой обмен конфиденциальной информацией будет происходить только после получения вашего явного и предварительного согласия.'),
('legal', 'privacy_policy_section_3_6', 'he', '**3.6 אנונימיזציה:** כאשר אנו משתפים מידע למטרות מחקר או סטטיסטיקה, אנו מבטיחים שהמידע לא ניתן לזיהוי אישי.'),
('legal', 'privacy_policy_section_3_6', 'en', '**3.6 Anonymization:** When we share information for research or statistical purposes, we ensure the information cannot be personally identified.'),
('legal', 'privacy_policy_section_3_6', 'ru', '**3.6 Анонимизация:** Когда мы делимся информацией в исследовательских или статистических целях, мы обеспечиваем невозможность персональной идентификации.'),
('legal', 'privacy_policy_section_3_7', 'he', '**3.7 גבולות גיאוגרפיים:** איננו מעבירים מידע אישי מחוץ לגבולות ישראל ללא הסכמה מפורשת.'),
('legal', 'privacy_policy_section_3_7', 'en', '**3.7 Geographic Boundaries:** We do not transfer personal information outside Israel''s borders without explicit consent.'),
('legal', 'privacy_policy_section_3_7', 'ru', '**3.7 Географические границы:** Мы не передаем персональную информацию за пределы Израиля без явного согласия.'),
('legal', 'privacy_policy_section_3_8', 'he', '**3.8 ביקורת ובקרה:** כל ספק שירות חיצוני עובר תהליכי אישור קפדניים וחותם על הסכמי סודיות מחמירים.'),
('legal', 'privacy_policy_section_3_8', 'en', '**3.8 Audit and Control:** Every external service provider undergoes strict approval processes and signs stringent confidentiality agreements.'),
('legal', 'privacy_policy_section_3_8', 'ru', '**3.8 Аудит и контроль:** Каждый внешний поставщик услуг проходит строгие процессы одобрения и подписывает жесткие соглашения о конфиденциальности.'),
('legal', 'privacy_policy_section_3_9', 'he', '**3.9 הגבלת זמן:** שיתוף מידע מוגבל לתקופה הנדרשת למטרה הספציפית בלבד.'),
('legal', 'privacy_policy_section_3_9', 'en', '**3.9 Time Limitation:** Information sharing is limited to the period required for the specific purpose only.'),
('legal', 'privacy_policy_section_3_9', 'ru', '**3.9 Ограничение времени:** Обмен информацией ограничен периодом, необходимым для конкретной цели.'),
('legal', 'privacy_policy_section_3_title', 'he', '**3. שיתוף מידע**'),
('legal', 'privacy_policy_section_3_title', 'en', '**3. Information Sharing**'),
('legal', 'privacy_policy_section_3_title', 'ru', '**3. Обмен информацией**'),
('legal', 'privacy_policy_section_4_1', 'he', '**4.1 הצפנה:** אנו משתמשים בטכנולוגיות הצפנה מתקדמות (SSL/TLS) להגנה על המידע שלכם במהלך העברה דרך האינטרנט.'),
('legal', 'privacy_policy_section_4_1', 'en', '**4.1 Encryption:** We use advanced encryption technologies (SSL/TLS) to protect your information during transmission over the internet.'),
('legal', 'privacy_policy_section_4_1', 'ru', '**4.1 Шифрование:** Мы используем передовые технологии шифрования (SSL/TLS) для защиты вашей информации во время передачи через интернет.'),
('legal', 'privacy_policy_section_4_2', 'he', '**4.2 גישה מוגבלת:** הגישה למידע האישי שלכם מוגבלת לעובדים מורשים הזקוקים למידע לביצוע תפקידיהם.'),
('legal', 'privacy_policy_section_4_2', 'en', '**4.2 Limited Access:** Access to your personal information is limited to authorized employees who need the information to perform their duties.'),
('legal', 'privacy_policy_section_4_2', 'ru', '**4.2 Ограниченный доступ:** Доступ к вашей персональной информации ограничен авторизованными сотрудниками, которым нужна информация для выполнения их обязанностей.'),
('legal', 'privacy_policy_section_4_3', 'he', '**4.3 גיבוי ושחזור:** אנו מבצעים גיבויי נתונים קבועים ושומרים על תוכניות שחזור חירום.'),
('legal', 'privacy_policy_section_4_3', 'en', '**4.3 Backup and Recovery:** We perform regular data backups and maintain emergency recovery plans.'),
('legal', 'privacy_policy_section_4_3', 'ru', '**4.3 Резервное копирование и восстановление:** Мы выполняем регулярное резервное копирование данных и поддерживаем планы экстренного восстановления.'),
('legal', 'privacy_policy_section_4_4', 'he', '**4.4 עדכוני אבטחה:** אנו מעדכנים באופן קבוע את מערכות האבטחה שלנו להתמודדות עם איומים חדשים.'),
('legal', 'privacy_policy_section_4_4', 'en', '**4.4 Security Updates:** We regularly update our security systems to address new threats.'),
('legal', 'privacy_policy_section_4_4', 'ru', '**4.4 Обновления безопасности:** Мы регулярно обновляем наши системы безопасности для противодействия новым угрозам.'),
('legal', 'privacy_policy_section_4_5', 'he', '**4.5 ביקורות אבטחה:** אנו עורכים ביקורות אבטחה תקופתיות על ידי גורמים חיצוניים מקצועיים.'),
('legal', 'privacy_policy_section_4_5', 'en', '**4.5 Security Audits:** We conduct periodic security audits by professional external parties.'),
('legal', 'privacy_policy_section_4_5', 'ru', '**4.5 Аудиты безопасности:** Мы проводим периодические аудиты безопасности профессиональными внешними сторонами.'),
('legal', 'privacy_policy_section_4_title', 'he', '**4. אבטחת מידע**'),
('legal', 'privacy_policy_section_4_title', 'en', '**4. Information Security**'),
('legal', 'privacy_policy_section_4_title', 'ru', '**4. Безопасность информации**'),
('legal', 'privacy_policy_section_5_1', 'he', '**5.1 זכות גישה:** יש לכם זכות לבקש גישה למידע האישי שאנו שומרים עליכם.'),
('legal', 'privacy_policy_section_5_1', 'en', '**5.1 Right of Access:** You have the right to request access to the personal information we hold about you.'),
('legal', 'privacy_policy_section_5_1', 'ru', '**5.1 Право доступа:** У вас есть право запросить доступ к персональной информации, которую мы храним о вас.'),
('legal', 'privacy_policy_section_5_10', 'he', '**5.10 ללא תשלום:** מימוש זכויותיכם הוא ללא תשלום, למעט במקרים של בקשות מרובות או בלתי סבירות.'),
('legal', 'privacy_policy_section_5_10', 'en', '**5.10 No Fee:** Exercising your rights is free of charge, except in cases of multiple or unreasonable requests.'),
('legal', 'privacy_policy_section_5_10', 'ru', '**5.10 Без платы:** Осуществление ваших прав бесплатно, за исключением случаев множественных или неразумных запросов.'),
('legal', 'privacy_policy_section_5_11', 'he', '**5.11 אימות זהות:** אנו עשויים לבקש אימות זהות לפני מימוש זכויותיכם.'),
('legal', 'privacy_policy_section_5_11', 'en', '**5.11 Identity Verification:** We may request identity verification before exercising your rights.'),
('legal', 'privacy_policy_section_5_11', 'ru', '**5.11 Проверка личности:** Мы можем запросить проверку личности перед осуществлением ваших прав.'),
('legal', 'privacy_policy_section_5_12', 'he', '**5.12 תיעוד בקשות:** כל בקשה מתועדת ומטופלת באופן מקצועי.'),
('legal', 'privacy_policy_section_5_12', 'en', '**5.12 Request Documentation:** Every request is documented and handled professionally.'),
('legal', 'privacy_policy_section_5_12', 'ru', '**5.12 Документирование запросов:** Каждый запрос документируется и обрабатывается профессионально.'),
('legal', 'privacy_policy_section_5_13', 'he', '**5.13 ייעוץ משפטי:** יש לכם זכות לקבל ייעוץ משפטי בעניינים הקשורים לפרטיות.'),
('legal', 'privacy_policy_section_5_13', 'en', '**5.13 Legal Counsel:** You have the right to receive legal counsel on privacy matters.'),
('legal', 'privacy_policy_section_5_13', 'ru', '**5.13 Юридическая консультация:** У вас есть право получить юридическую консультацию по вопросам конфиденциальности.'),
('legal', 'privacy_policy_section_5_14', 'he', '**5.14 עדכוני סטטוס:** נעדכן אתכם על התקדמות הטיפול בבקשתכם.'),
('legal', 'privacy_policy_section_5_14', 'en', '**5.14 Status Updates:** We will update you on the progress of handling your request.'),
('legal', 'privacy_policy_section_5_14', 'ru', '**5.14 Обновления статуса:** Мы будем обновлять вас о ходе обработки вашего запроса.'),
('legal', 'privacy_policy_section_5_15', 'he', '**5.15 שמירת התכתבות:** כל התכתבות בנושא זכויותיכם תישמר למשך 7 שנים.'),
('legal', 'privacy_policy_section_5_15', 'en', '**5.15 Communication Retention:** All communication regarding your rights will be retained for 7 years.'),
('legal', 'privacy_policy_section_5_15', 'ru', '**5.15 Хранение переписки:** Вся переписка касательно ваших прав будет храниться в течение 7 лет.'),
('legal', 'privacy_policy_section_5_2', 'he', '**5.2 זכות תיקון:** יש לכם זכות לבקש תיקון או עדכון של מידע שגוי או לא מדויק.'),
('legal', 'privacy_policy_section_5_2', 'en', '**5.2 Right of Correction:** You have the right to request correction or updating of incorrect or inaccurate information.')
) AS v(screen_location, content_key, lang, content_value)
JOIN content_items ci ON ci.screen_location = v.screen_location AND ci.content_key = v.content_key
ON CONFLICT (content_item_id, language_code) DO UPDATE SET
  content_value = EXCLUDED.content_value,
  status = EXCLUDED.status;

INSERT INTO content_translations (content_item_id, language_code, content_value, status)
