('global_components', 'lawyers_step_5_desc', 'he', 'אתם מקבלים:\\n\\nלקוחות בלעדיים\\nגישה לפלטפורמה דיגיטלית ותמיכה 24/7\\nחיסכון בעלויות פרסום\\n\\nאנו מוציאים חשבון על פי היקף העבודה ומספר הלקוחות שהועברו אליכם בתנאים אישיים'),
('global_components', 'lawyers_step_5_desc', 'en', 'You receive:\\n\\nExclusive clients\\nAccess to Digital platform and 24/7 support\\nSavings on advertising costs\\n\\nWe bill based on work volume and number of clients provided to you on individual terms'),
('global_components', 'lawyers_step_5_desc', 'ru', 'Вы получаете:\\n\\nЭксклюзивных клиентов\\nДоступ к цифровой платформе и поддержку 24/7\\nЭкономию на расходах на рекламу\\n\\nМы выставляем счет на основе объема работы и количества предоставленных вам клиентов на индивидуальных условиях'),
('global_components', 'lawyers_step_5_title', 'he', 'תשלום חודשי עבור השירותים שלנו'),
('global_components', 'lawyers_step_5_title', 'en', 'Monthly Payment for Our Services'),
('global_components', 'lawyers_step_5_title', 'ru', 'Ежемесячная оплата за наши услуги'),
